configuration.tbelDecoder:
// Parse JSON safely
var json = decodeToJson(payload);
if (json == null) {
  json = {};
}

// Telemetry object
var telemetry = {};

// ---- DEVICE STATUS ----
if (json.slave_id != null) {
  telemetry.slave_id = json.slave_id * 1; // force number
}

if (json.active != null) {
  telemetry.active = !!json.active; // force boolean
}

if (json.switch_closed != null) {
  telemetry.switch_closed = !!json.switch_closed; // force boolean
}

if (json.fault_status != null) {
  telemetry.fault_status = json.fault_status * 1; // force number
}

if (json.alarm_status != null) {
  telemetry.alarm_status = json.alarm_status * 1; // force number
}

if (json.last_event != null) {
  telemetry.last_event = json.last_event;
}

// ---- ELECTRICAL MEASUREMENTS ----
if (json.l1_current_a != null) {
  telemetry.l1_current_a = json.l1_current_a * 1; // force number
}

if (json.l1_voltage_v != null) {
  telemetry.l1_voltage_v = json.l1_voltage_v * 1; // force number
}

if (json.l1_power_w != null) {
  telemetry.l1_power_w = json.l1_power_w * 1; // force number
}

if (json.power_factor != null) {
  telemetry.power_factor = json.power_factor * 1; // force number
}

// Attributes (empty for now)
var attributes = {};

return {
  deviceName: "lab1 station2",
  deviceType: "test",
  attributes: attributes,
  telemetry: telemetry
};
